107→function rowToEntry(row: SnippetRow): SnippetEntry {
108→  const parsed = new Date(row.created_at);
109→  const createdAt = isNaN(parsed.getTime()) ? new Date() : parsed;
110→
111→  let tags: {
112→    text: string;
113→    color?: TagColor;
114→  }[] = [];
115→  try {
116→    const raw = JSON.parse(row.tags);
117→    if (Array.isArray(raw)) {
118→      tags = raw.map((t: {
119→        text?: string;
120→        color?: string;
121→      }) => ({
122→        text: typeof t.text === 'string' ? t.text : '',
123→        color:
124→          typeof t.color === 'string' && isTagColor(t.color)
125→            ? t.color
126→            : undefined,
127→      }));
128→    }
129→  } catch {
130→    /* invalid JSON, use empty tags */
131→  }
132→
133→  return {
134→    id: row.id,
135→    name: row.name,
136→    keyword: row.keyword,
137→    content: row.content,
138→    category: isSnippetCategory(row.category) ? row.category : 'general',
139→    tags,
140→    createdAt,
141→  };
142→}
