207→    if (snippet) {
208→      return {
209→        name: snippet.name,
210→        keyword: snippet.keyword,
211→        snippet: snippet.content,
212→        category: snippet.category,
213→        tags: snippet.tags.map(t => t.text.toLowerCase()),
214→      };
215→    }
216→    return INITIAL_SNIPPET_FORM;
217→  });
218→  const [errors, setErrors] = useState<
219→    Partial<Record<keyof SnippetFormState, string>>
220→  >({});
221→
222→  const handleSubmit = useCallback(() => {
223→    const newErrors: Partial<Record<keyof SnippetFormState, string>> = {};
224→    if (!form.name.trim()) {
225→      newErrors.name = 'Name is required';
226→    }
227→    if (!form.snippet.trim()) {
228→      newErrors.snippet = 'Snippet content is required';
229→    }
230→    setErrors(newErrors);
231→    if (Object.keys(newErrors).length > 0) return;
232→    onSubmit(form);
233→  }, [
234→    form,
235→    onSubmit,
236→  ]);
237→
238→  useKeyboardShortcut(
239→    {
240→      key: 'Enter',
241→      meta: true,
242→    },
243→    handleSubmit,
244→  );
