248→      <FormTextField
249→        label="Name"
250→        value={form.name}
251→        onChange={v =>
252→          setForm(prev => ({
253→            ...prev,
254→            name: v,
255→          }))
256→        }
257→        placeholder="e.g. Email Signature"
258→        error={errors.name}
259→        autoFocus
260→      />
261→      <FormTextField
262→        label="Keyword"
263→        value={form.keyword}
264→        onChange={v =>
265→          setForm(prev => ({
266→            ...prev,
267→            keyword: v,
268→          }))
269→        }
270→        placeholder="e.g. !sig"
271→        description="Type this to expand the snippet"
272→      />
273→      <FormDropdown
274→        label="Category"
275→        value={form.category}
276→        onChange={v => {
277→          if (isSnippetCategory(v)) {
278→            setForm(prev => ({
279→              ...prev,
280→              category: v,
281→            }));
282→          }
283→        }}
284→        options={FORM_CATEGORY_OPTIONS}
285→        placeholder="Select a category"
286→      />
287→      <FormTagPicker
288→        label="Tags"
289→        value={form.tags}
290→        onChange={v =>
291→          setForm(prev => ({
292→            ...prev,
293→            tags: v,
294→          }))
295→        }
296→        options={FORM_TAG_OPTIONS}
297→        placeholder="Add tags..."
298→        description="Categorize your snippet with tags"
299→      />
300→      <FormTextArea
301→        label="Snippet"
302→        value={form.snippet}
303→        onChange={v =>
304→          setForm(prev => ({
305→            ...prev,
306→            snippet: v,
307→          }))
308→        }
309→        placeholder="Enter your snippet content..."
310→        error={errors.snippet}
311→        rows={5}
312→      />
313→    </Form>
314→  );
